Row.code:
try {
    if (!fileName || fileName.indexOf("..") !== -1 || fileName.indexOf("/") !== -1 || fileName.indexOf("\\") !== -1) {
        throw new Error("fileName must not be empty or contain path separators or '..': " + fileName);
    }
    if (!folderName || folderName.indexOf("..") !== -1 || folderName.indexOf("/") !== -1 || folderName.indexOf("\\") !== -1) {
        throw new Error("folderName must not be empty or contain path separators or '..': " + folderName);
    }

    var zipPath = folderName + "/" + fileName;

    Things["SystemRepository"].SaveBinary({
        path: zipPath,
        content: zipContent
    });

    Things["SystemRepository"].ExtractZipArchive({
        zipFileName: zipPath,
        path: folderName
    });

    Resources["SourceControlFunctions"].ImportSourceControlledEntities({
        repositoryName: "SystemRepository",
        path: folderName,
        useDefaultDataProvider: true,
        withSubsystems: false,
        overwritePropertyValues: true,
        overwriteConfigurationTableValues: true
    });

    result = "Imported entities from " + zipPath + " into folder " + folderName + ".";
} catch (err) {
    logger.error("VPS.Development.MCP.Management_TS.ImportEntityZip failed: " + err.message);
    throw err;
}

var startTime = Date.now();
try {
    if (!thingName) {
        throw new Error("thingName must not be empty");
    }
    if (!serviceName) {
        throw new Error("serviceName must not be empty");
    }
    if (!Things[thingName]) {
        throw new Error("Thing '" + thingName + "' does not exist");
    }
    if (typeof Things[thingName][serviceName] !== "function") {
        throw new Error("Service '" + serviceName + "' does not exist on Thing '" + thingName + "'");
    }

    // params arrives as a ThingWorx-internal wrapper, not a plain JS object; JSON round-trip strips it, and empty objects must be omitted entirely — passing {} or the wrapper directly causes a platform "Invalid parameter type" error even for zero-param services.
    var callParams = params ? JSON.parse(JSON.stringify(params)) : {};
    var hasParams = false;
    for (var key in callParams) {
        hasParams = true;
        break;
    }
    var rawResult = hasParams ? Things[thingName][serviceName](callParams) : Things[thingName][serviceName]();

    var serializedResult;
    if (rawResult && typeof rawResult.ToJSON === "function") {
        serializedResult = rawResult.ToJSON();
    } else if (rawResult instanceof Date) {
        serializedResult = rawResult.toISOString();
    } else {
        serializedResult = rawResult;
    }

    // Probe for non-serializable results here (inside the try) rather than letting the platform's own JSON encoding of the ResultType discover the same failure outside this try/catch.
    JSON.stringify(serializedResult);
    result = {
        success: true,
        result: serializedResult,
        executionTimeMs: Date.now() - startTime,
        error: null
    };
} catch (err) {
    logger.error("VPS.Development.MCP.Management_TS.ExecuteService failed: " + err.message);
    result = {
        success: false,
        result: null,
        executionTimeMs: Date.now() - startTime,
        error: err.message
    };
}

try {
    var effectiveLogName = logName || "ApplicationLog";

    var effectiveStartDate = null;
    var effectiveEndDate = null;
    if (startTime || endTime) {
        effectiveStartDate = startTime || null;
        effectiveEndDate = endTime || null;
    } else if (sinceMinutes !== undefined && sinceMinutes !== null) {
        var nowMs = Date.now();
        effectiveStartDate = new Date(nowMs - (sinceMinutes * 60000)).toISOString();
        effectiveEndDate = new Date(nowMs).toISOString();
    }

    var effectiveMaxItems = (maxRows === undefined || maxRows === null) ? 50 : maxRows;
    if (effectiveMaxItems < 1) {
        effectiveMaxItems = 1;
    } else if (effectiveMaxItems > 200) {
        effectiveMaxItems = 200;
    }

    var effectiveSearchExpression = null;
    if (search) {
        effectiveSearchExpression = (search.indexOf("*") === -1) ? ("*" + search + "*") : search;
    }

    var retrieveParams = {
        logName: effectiveLogName,
        maxItems: effectiveMaxItems
    };
    if (effectiveStartDate) {
        retrieveParams.startDate = effectiveStartDate;
    }
    if (effectiveEndDate) {
        retrieveParams.endDate = effectiveEndDate;
    }
    if (effectiveSearchExpression) {
        retrieveParams.searchExpression = effectiveSearchExpression;
    }

    var logResult = Things["DefaultLogRetrievalStrategyThing"].RetrieveLogs(retrieveParams);

    var rows = [];
    for (var i = 0; i < logResult.rows.length; i++) {
        rows.push(logResult.rows[i]);
    }

    if (level) {
        var upperLevel = level.toUpperCase();
        rows = rows.filter(function (row) {
            return row.level && row.level.toUpperCase() === upperLevel;
        });
    }

    result = rows.map(function (row, idx) {
        var ts = row.timestamp;
        var isoTimestamp;
        try {
            isoTimestamp = (ts instanceof Date) ? ts.toISOString() : new Date(ts).toISOString();
        } catch (tsErr) {
            throw new Error("Row " + idx + " has an unparseable timestamp (" + ts + "): " + tsErr.message);
        }
        return {
            timestamp: isoTimestamp,
            level: row.level,
            source: row.origin,
            message: row.content
        };
    });
} catch (err) {
    logger.error("VPS.Development.MCP.Management_TS.GetLogEntries failed: " + err.message);
    throw err;
}

try {
    if (!projectName) {
        throw new Error("projectName must not be empty");
    }

    var effectiveIncludeDependents = (includeDependents !== undefined && includeDependents !== null) ? includeDependents : true;

    var scratchSuffix = String(Date.now());
    var scratchZipPath = "export-entities-scratch-" + scratchSuffix;
    var scratchExtractPath = "export-entities-scratch-extracted-" + scratchSuffix;

    var exportParams = {
        repositoryName: "SystemRepository",
        path: scratchZipPath,
        projectName: projectName,
        includeDependents: effectiveIncludeDependents
    };
    if (startDate) {
        exportParams.startDate = startDate;
    }
    if (endDate) {
        exportParams.endDate = endDate;
    }

    var exportPath = Resources["SourceControlFunctions"].ExportSourceControlledEntitiesToZipFile(exportParams);
    var repoRelativePath = String(exportPath).replace("/FileRepositories/SystemRepository/", "");

    var zipBlob = Things["SystemRepository"].LoadBinary({ path: repoRelativePath });
    if (!zipBlob) {
        throw new Error("LoadBinary returned no content for " + repoRelativePath);
    }
    var base64Content = zipBlob;

    Things["SystemRepository"].ExtractZipArchive({
        zipFileName: repoRelativePath,
        path: scratchExtractPath
    });

    var manifest = [];
    var extractedFilePaths = [];

    // ListFiles/ListDirectories row shape confirmed live via a temporary
    // probe (since removed): both return rows with a bare `.name` field
    // (accessed via `.rows`), so recursive path-joining below is safe.
    var walk = function (relativePath) {
        var files = Things["SystemRepository"].ListFiles({ path: scratchExtractPath + (relativePath ? "/" + relativePath : "") });
        var fileRows = (files && files.rows) ? files.rows : [];
        for (var i = 0; i < fileRows.length; i++) {
            var fileName = fileRows[i].name;
            var entryRelativePath = relativePath ? relativePath + "/" + fileName : fileName;
            manifest.push(entryRelativePath);
            extractedFilePaths.push(scratchExtractPath + "/" + entryRelativePath);
        }

        var dirs = Things["SystemRepository"].ListDirectories({ path: scratchExtractPath + (relativePath ? "/" + relativePath : "") });
        var dirRows = (dirs && dirs.rows) ? dirs.rows : [];
        for (var j = 0; j < dirRows.length; j++) {
            var dirName = dirRows[j].name;
            var subPath = relativePath ? relativePath + "/" + dirName : dirName;
            walk(subPath);
        }
    };

    walk("");

    try {
        Things["SystemRepository"].DeleteFile({ path: repoRelativePath });
    } catch (cleanupErr) {
        logger.error("VPS.Development.MCP.Management_TS.ExportEntities cleanup failed for " + repoRelativePath + ": " + cleanupErr.message);
    }
    for (var k = 0; k < extractedFilePaths.length; k++) {
        try {
            Things["SystemRepository"].DeleteFile({ path: extractedFilePaths[k] });
        } catch (cleanupErr2) {
            logger.error("VPS.Development.MCP.Management_TS.ExportEntities cleanup failed for " + extractedFilePaths[k] + ": " + cleanupErr2.message);
        }
    }

    result = {
        zipContent: base64Content,
        manifest: manifest,
        entityCount: manifest.length
    };
} catch (err) {
    logger.error("VPS.Development.MCP.Management_TS.ExportEntities failed: " + err.message);
    throw err;
}

try {
    var validTypes = ["Thing", "ThingTemplate", "ThingShape", "DataShape"];
    if (validTypes.indexOf(entityType) === -1) {
        throw new Error("entityType must be one of Thing, ThingTemplate, ThingShape, DataShape, got: " + entityType);
    }
    if (!entityName) {
        throw new Error("entityName must not be empty");
    }

    var flattenRow = function (row) {
        var flat = {};
        for (var key in row) {
            var value = row[key];
            if (value && typeof value === "object" && typeof value.rows !== "undefined") {
                flat[key] = flattenInfoTable(value);
            } else {
                flat[key] = value;
            }
        }
        return flat;
    };

    var flattenInfoTable = function (infoTable) {
        if (!infoTable || !infoTable.rows) {
            return [];
        }
        var out = [];
        for (var i = 0; i < infoTable.rows.length; i++) {
            out.push(flattenRow(infoTable.rows[i]));
        }
        return out;
    };

    var filterLocal = function (infoTable, ownerName) {
        var arr = flattenInfoTable(infoTable);
        var out = [];
        for (var i = 0; i < arr.length; i++) {
            if (arr[i].sourceName === ownerName) {
                out.push(arr[i]);
            }
        }
        return out;
    };

    if (entityType === "DataShape") {
        if (!DataShapes[entityName]) {
            throw new Error("DataShape '" + entityName + "' does not exist");
        }
        result = {
            entityName: entityName,
            entityType: entityType,
            fields: flattenInfoTable(DataShapes[entityName].GetFieldDefinitions())
        };
    } else {
        var collection;
        if (entityType === "Thing") {
            collection = Things;
        } else if (entityType === "ThingTemplate") {
            collection = ThingTemplates;
        } else {
            collection = ThingShapes;
        }

        var entity = collection[entityName];
        if (!entity) {
            throw new Error(entityType + " '" + entityName + "' does not exist");
        }

        var services = filterLocal(entity.GetServiceDefinitions(), entityName);
        var properties = filterLocal(entity.GetPropertyDefinitions(), entityName);
        var events = filterLocal(entity.GetEventDefinitions(), entityName);

        var tableNames = flattenInfoTable(entity.GetConfigurationTables());
        var configurationTables = [];
        for (var t = 0; t < tableNames.length; t++) {
            var tableDef = flattenInfoTable(entity.GetConfigurationTableDefinition({ tableName: tableNames[t].name }));
            configurationTables.push(tableDef[0]);
        }

        result = {
            entityName: entityName,
            entityType: entityType,
            services: services,
            properties: properties,
            events: events,
            configurationTables: configurationTables
        };

        if (entityType === "Thing") {
            var shapeRows = flattenInfoTable(entity.GetImplementedShapes());
            var shapeNames = [];
            for (var s = 0; s < shapeRows.length; s++) {
                shapeNames.push(shapeRows[s].name);
            }
            result.inheritance = {
                thingTemplate: String(entity.thingTemplate),
                implementedShapes: shapeNames
            };
        }
    }
} catch (err) {
    logger.error("VPS.Development.MCP.Management_TS.GetEntityDefinition failed: " + err.message);
    throw err;
}
